using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");
Console.WriteLine($"  Properties: {personInfo.Properties.Count}");

// Round-trip using the typed metadata
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
var back = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"  Round-trip: {back}");

// 2) Probe without throwing — TryGetTypeInfo returns false if not resolvable
bool havePerson = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed);
Console.WriteLine($"\nTryGetTypeInfo(Person)  → found={havePerson}, type={probed?.Type.Name}");

// Use a resolver that only knows about one type, so another type will fail
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

bool haveInt = limited.TryGetTypeInfo(typeof(int), out JsonTypeInfo? intInfo);
Console.WriteLine($"TryGetTypeInfo(int)     → found={haveInt}, info is null={intInfo is null}");

// Branch on availability
if (limited.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("✓ Person metadata available in limited resolver");
if (!limited.TryGetTypeInfo(typeof(int), out _))
    Console.WriteLine("✗ int metadata NOT available — no exception thrown");

// --- Types ---
public record Person(string Name, int Age);

// A resolver that only resolves Person
file class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private static readonly DefaultJsonTypeInfoResolver _inner = new();
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
        => type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}
EOF

